CREATE TYPE "account_status" AS ENUM (
  'active',
  'cooldown',
  'disabled',
  'banned',
  'error'
);

CREATE TYPE "task_status" AS ENUM (
  'queued',
  'scheduled',
  'in_progress',
  'retry',
  'done',
  'failed',
  'cancelled',
  'stuck'
);

CREATE TYPE "attempt_status" AS ENUM (
  'running',
  'success',
  'error',
  'timeout'
);

CREATE TYPE "task_op_account_role" AS ENUM (
  'primary',
  'source',
  'target'
);

CREATE TABLE "resource_op_types" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" text UNIQUE NOT NULL,
  "name" text,
  "rph_limit" integer NOT NULL,
  "reserve_percent" numeric NOT NULL DEFAULT 10,
  "is_enabled" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "accounts" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "telegram_account_id" text,
  "session_name" text UNIQUE NOT NULL,
  "status" account_status NOT NULL DEFAULT 'active',
  "is_enabled" boolean NOT NULL DEFAULT true,
  "cooldown_until" timestamptz,
  "current_task_id" bigint,
  "last_used_at" timestamptz,
  "last_error" text,
  "last_error_at" timestamptz,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "task_types" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" text UNIQUE NOT NULL,
  "name" text NOT NULL,
  "description" text,
  "is_enabled" boolean NOT NULL DEFAULT false,
  "default_priority" integer NOT NULL,
  "min_available_resource_percent" integer NOT NULL,
  "requires_specific_account" boolean NOT NULL DEFAULT false,
  "uses_two_accounts" boolean NOT NULL DEFAULT false,
  "max_attempts" integer NOT NULL DEFAULT 5,
  "retry_delay_seconds" integer NOT NULL DEFAULT 10,
  "retry_backoff_multiplier" numeric NOT NULL DEFAULT 2,
  "max_retry_delay_seconds" integer NOT NULL DEFAULT 1800,
  "target_queue_size" integer,
  "max_postpone_count" integer NOT NULL DEFAULT 100,
  "task_timeout_seconds" integer NOT NULL DEFAULT 300,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "task_type_ops" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "task_type_id" integer NOT NULL,
  "op_type_id" integer NOT NULL,
  "units_per_execution" integer NOT NULL DEFAULT 1,
  "account_role" task_op_account_role NOT NULL DEFAULT 'primary'
);

-- platforms: справочник из Lidogen_main_DB.sql (FK source_channels.platform_id).
-- IF NOT EXISTS — накат очереди поверх существующей main DB без дублирования таблицы.
CREATE TABLE IF NOT EXISTS "platforms" (
  "id" bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  "code" varchar NOT NULL,
  "name" varchar NOT NULL,
  "description" text,
  "website_url" varchar,
  "icon_url" varchar,
  "is_active" boolean NOT NULL DEFAULT true,
  "is_in_testing" boolean NOT NULL DEFAULT false,
  "can_be_source" boolean NOT NULL DEFAULT true,
  "can_be_delivery" boolean NOT NULL DEFAULT true,
  "can_be_feedback_source" boolean NOT NULL DEFAULT true,
  "metadata" jsonb,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE UNIQUE INDEX IF NOT EXISTS "uq_platforms_code_ci"
  ON "platforms" (lower("code"));

-- source_channels: Lidogen_main_DB + поля балансировщика (ТЗ §5.1, A8).
-- Идентичность канала: (platform_id, external_channel_id). channel_ref — в payload задачи / external_url.
-- При интеграции с существующей main DB использовать ALTER ADD COLUMN вместо CREATE.
CREATE TABLE "source_channels" (
  "id" bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  "platform_id" bigint NOT NULL,
  "external_channel_id" varchar NOT NULL,
  "name" varchar,
  "description" text,
  "external_url" varchar,
  "image_url" varchar,
  "metadata" jsonb,
  "linked_projects_count" integer NOT NULL DEFAULT 0,
  "is_active" boolean NOT NULL DEFAULT true,
  "assigned_account_id" bigint,
  "extra_data_collected" boolean NOT NULL DEFAULT false,
  "last_updated_at" timestamptz,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now()),
  CONSTRAINT "chk_source_channels_linked_projects_count" CHECK ("linked_projects_count" >= 0),
  CONSTRAINT "uq_source_channels_platform_external" UNIQUE ("platform_id", "external_channel_id")
);

CREATE TABLE "task_queue" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "task_type_id" integer NOT NULL,
  "task_type_code" text NOT NULL,
  "status" task_status NOT NULL DEFAULT 'queued',
  "priority" integer NOT NULL,
  "channel_id" bigint,
  "account_id" bigint,
  "source_account_id" bigint,
  "target_account_id" bigint,
  "payload" jsonb NOT NULL DEFAULT '{}',
  "dedup_key" text,
  "run_after" timestamptz NOT NULL DEFAULT (now()),
  "locked_by" text,
  "locked_at" timestamptz,
  "locked_until" timestamptz,
  "attempt_count" integer NOT NULL DEFAULT 0,
  "postpone_count" integer NOT NULL DEFAULT 0,
  "max_attempts" integer NOT NULL,
  "last_error" text,
  "last_error_at" timestamptz,
  "started_at" timestamptz,
  "finished_at" timestamptz,
  "created_by" text,
  "created_at" timestamptz NOT NULL DEFAULT (now()),
  "updated_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "task_attempts" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "task_id" bigint NOT NULL,
  "task_type_id" integer NOT NULL,
  "account_id" bigint NOT NULL,
  "source_account_id" bigint,
  "target_account_id" bigint,
  "attempt_number" integer NOT NULL,
  "status" attempt_status NOT NULL,
  "error_code" text,
  "error_message" text,
  "started_at" timestamptz NOT NULL,
  "finished_at" timestamptz,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

CREATE TABLE "account_resource_usage" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "account_id" bigint NOT NULL,
  "op_type_id" integer NOT NULL,
  "task_id" bigint NOT NULL,
  "task_attempt_id" bigint,
  "task_type_id" integer NOT NULL,
  "units" integer NOT NULL DEFAULT 1,
  "created_at" timestamptz NOT NULL DEFAULT (now())
);

